function solve(prices, strategy, k) {
    let maxProfit = 0;
    const n = prices.length;

    // Calculate the original profit
    let profit = 0;
    for (let i = 0; i < n; i++) {
        profit += strategy[i] * prices[i];
    }
    maxProfit = profit;

    // Try to improve the profit by modifying a subarray of length k
    for (let i = 0; i <= n - k; i++) {
        // Calculate the profit change if we modify the subarray from i to i + k - 1
        let change = 0;
        // Original strategy in the subarray: first k/2 elements are -1, next k/2 are 1
        for (let j = 0; j < k; j++) {
            if (j < k / 2) {
                // Original is -1, changing to 0
                change += (-1 * prices[i + j]) - (0 * prices[i + j]);
            } else {
                // Original is 1, changing to 1 (no change)
                change += (1 * prices[i + j]) - (1 * prices[i + j]);
            }
        }
        // Update maxProfit if this modification gives a better profit
        maxProfit = Math.max(maxProfit, profit + change);
    }

    return maxProfit;
}

